port androidx.compose.ui.graphics.vector.ImageVector import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.text.style.TextAlign import androidx.compose.ui.unit.dp import androidx.compose.ui.res.stringResource import androidx.appcompat.app.AppCompatDelegate import androidx.core.os.LocaleListCompat import androidx.compose.material.icons.filled.Translate import com.hcwebhook.app.FlavorUtils import com.hcwebhook.app.HealthDataType import com.hcwebhook.app.R import kotlinx.coroutines.launch
@OptIn(ExperimentalFoundationApi::class) @Composable fun OnboardingScreen(onFinish: () -> Unit) { val pageCount = if (FlavorUtils.isPlayStore) 4 else 3 val lastPage = pageCount - 1 val pagerState = rememberPagerState(pageCount = { pageCount }) val scope = rememberCoroutineScope() var showSkipDialog by remember { mutableStateOf(false) }
if (showSkipDialog) { AlertDialog( onDismissRequest = { showSkipDialog = false }, title = { Text(stringResource(R.string.onboarding_skip_dialog_title)) }, text = { Text(stringResource(R.string.onboarding_skip_dialog_text)) }, confirmButton = { TextButton(onClick = { showSkipDialog = false onFinish() }) { Text(stringResource(R.string.onboarding_skip)) } }, dismissButton = { TextButton(onClick = { showSkipDialog = false }) { Text(stringResource(R.string.onboarding_cancel)) } } ) }
Scaffold( contentWindowInsets = WindowInsets(0.dp), topBar = { Row( modifier = Modifier .fillMaxWidth() .padding(horizontal = 16.dp, vertical = 8.dp) .statusBarsPadding(), horizontalArrangement = Arrangement.End ) { LanguageSelector() } }, bottomBar = { Column( modifier = Modifier .fillMaxWidth() .padding(horizontal = 24.dp) .padding(bottom = 32.dp, top = 16.dp), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.spacedBy(16.dp) ) { Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) { repeat(pageCount) { index -> val color by animateColorAsState( targetValue = if (pagerState.currentPage == index) MaterialTheme.colorScheme.primary else MaterialTheme.colorScheme.outlineVariant, label = "dot_color" ) Box( modifier = Modifier .size(if (pagerState.currentPage == index) 10.dp else 8.dp) .background(color, CircleShape) ) } }
Button( onClick = { if (pagerState.currentPage < lastPage) { scope.launch { pagerState.animateScrollToPage(pagerState.currentPage + 1) } } else { onFinish() } }, modifier = Modifier.fillMaxWidth() ) { Text(if (pagerState.currentPage < lastPage) stringResource(R.string.onboarding_next) else stringResource(R.string.onboarding_get_started)) }
if (pagerState.currentPage < lastPage) { TextButton(onClick = { showSkipDialog = true }) { Text(stringResource(R.string.onboarding_skip), color = MaterialTheme.colorScheme.onSurfaceVariant) } } } } ) { padding -> HorizontalPager( state = pagerState, modifier = Modifier .fillMaxSize() .padding(padding) .statusBarsPadding() ) { page -> when (page) { 0 -> WelcomePage() 1 -> DataTypesPage() 2 -> PrivacyPage() 3 -> ThankYouPage() } } } }
@Composable private fun WelcomePage() { Column( modifier = Modifier .fillMaxSize() .padding(horizontal = 32.dp) .verticalScroll(rememberScrollState()), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { Icon( imageVector = Icons.Filled.Webhook, contentDescription = null, modifier = Modifier.size(72.dp), tint = MaterialTheme.colorScheme.primary ) Spacer(modifier = Modifier.height(24.dp)) Text( text = stringResource(R.string.onboarding_welcome_title), style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center ) Spacer(modifier = Modifier.height(12.dp)) Text( text = stringResource(R.string.onboarding_welcome_subtitle), style = MaterialTheme.typography.bodyLarge, textAlign = TextAlign.Center, color = MaterialTheme.colorScheme.onSurfaceVariant ) Spacer(modifier = Modifier.height(32.dp)) FeatureRow( icon = Icons.Filled.CheckCircle, title = stringResource(R.string.onboarding_feature1_title), description = stringResource(R.string.onboarding_feature1_desc) ) Spacer(modifier = Modifier.height(16.dp)) FeatureRow( icon = Icons.Filled.Webhook, title = stringResource(R.string.onboarding_feature2_title), description = stringResource(R.string.onboarding_feature2_desc) ) Spacer(modifier = Modifier.height(16.dp)) FeatureRow( icon = Icons.Filled.Lock, title = stringResource(R.string.onboarding_feature3_title), description = stringResource(R.string.onboarding_feature3_desc) ) } }
@Composable private fun DataTypesPage() { Column( modifier = Modifier .fillMaxSize() .verticalScroll(rememberScrollState()) .padding(horizontal = 24.dp) .padding(bottom = 24.dp) ) { Spacer(modifier = Modifier.height(24.dp)) Text( text = stringResource(R.string.onboarding_datatypes_title), style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold ) Spacer(modifier = Modifier.height(4.dp)) Text( text = stringResource(R.string.onboarding_datatypes_desc, HealthDataType.entries.size), style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant ) Spacer(modifier = Modifier.height(20.dp))
val groups = mapOf( stringResource(R.string.onboarding_group_activity) to listOf( HealthDataType.STEPS, HealthDataType.DISTANCE, HealthDataType.ACTIVE_CALORIES, HealthDataType.TOTAL_CALORIES, HealthDataType.EXERCISE ), stringResource(R.string.onboarding_group_heart_vitals) to listOf( HealthDataType.HEART_RATE, HealthDataType.HEART_RATE_VARIABILITY, HealthDataType.RESTING_HEART_RATE, HealthDataType.BLOOD_PRESSURE, HealthDataType.OXYGEN_SATURATION, HealthDataType.RESPIRATORY_RATE, HealthDataType.BODY_TEMPERATURE, HealthDataType.SKIN_TEMPERATURE, HealthDataType.BLOOD_GLUCOSE ), stringResource(R.string.onboarding_group_sleep) to listOf( HealthDataType.SLEEP ), stringResource(R.string.onboarding_group_body_composition) to listOf( HealthDataType.WEIGHT, HealthDataType.HEIGHT, HealthDataType.BODY_FAT, HealthDataType.LEAN_BODY_MASS, HealthDataType.BONE_MASS, HealthDataType.BASAL_METABOLIC_RATE, HealthDataType.VO2_MAX ), stringResource(R.string.onboarding_group_nutrition) to listOf( HealthDataType.NUTRITION, HealthDataType.HYDRATION ) )
groups.forEach { (groupName, types) -> Text( text = groupName, style = MaterialTheme.typography.labelLarge, color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.SemiBold ) Spacer(modifier = Modifier.height(8.dp)) types.forEach { type -> Row( modifier = Modifier.padding(bottom = 10.dp), horizontalArrangement = Arrangement.spacedBy(12.dp), verticalAlignment = Alignment.Top ) { Icon( imageVector = iconForDataType(type), contentDescription = null, tint = MaterialTheme.colorScheme.primary, modifier = Modifier.size(18.dp).padding(top = 2.dp) ) Column { Text( text = stringResource(id = type.nameResId), style = MaterialTheme.typography.bodyMedium, fontWeight = FontWeight.Medium ) Text( text = stringResource(id = type.rationaleResId), style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant ) } } } HorizontalDivider( modifier = Modifier.padding(vertical = 8.dp), color = MaterialTheme.colorScheme.outlineVariant ) } Spacer(modifier = Modifier.height(16.dp)) } }
@Composable private fun PrivacyPage() { Column( modifier = Modifier .fillMaxSize() .padding(horizontal = 32.dp) .verticalScroll(rememberScrollState()), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { Icon( imageVector = Icons.Filled.Lock, contentDescription = null, modifier = Modifier.size(72.dp), tint = MaterialTheme.colorScheme.primary ) Spacer(modifier = Modifier.height(24.dp)) Text( text = stringResource(R.string.onboarding_privacy_title), style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center ) Spacer(modifier = Modifier.height(12.dp)) Text( text = stringResource(R.string.onboarding_privacy_subtitle), style = MaterialTheme.typography.bodyLarge, textAlign = TextAlign.Center, color = MaterialTheme.colorScheme.onSurfaceVariant ) Spacer(modifier = Modifier.height(32.dp))
val points = listOf( stringResource(R.string.onboarding_privacy_p1), stringResource(R.string.onboarding_privacy_p2), stringResource(R.string.onboarding_privacy_p3), stringResource(R.string.onboarding_privacy_p4), stringResource(R.string.onboarding_privacy_p5) )
points.forEach { point -> Row( modifier = Modifier .fillMaxWidth() .padding(bottom = 12.dp), horizontalArrangement = Arrangement.spacedBy(12.dp) ) { Icon( imageVector = Icons.Filled.CheckCircle, contentDescription = null, tint = MaterialTheme.colorScheme.primary, modifier = Modifier .size(20.dp) .padding(top = 2.dp) ) Text( text = point, style = MaterialTheme.typography.bodyMedium, color = MaterialTheme.colorScheme.onSurfaceVariant ) } }
Spacer(modifier = Modifier.height(24.dp)) Text( text = stringResource(R.string.onboarding_privacy_footer), style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant, textAlign = TextAlign.Center )
if (FlavorUtils.isPlayStore) { Spacer(modifier = Modifier.height(24.dp)) Card( colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.errorContainer) ) { Row( modifier = Modifier.padding(16.dp), horizontalArrangement = Arrangement.spacedBy(12.dp), verticalAlignment = Alignment.Top ) { Icon( imageVector = Icons.Filled.Warning, contentDescription = null, tint = MaterialTheme.colorScheme.onErrorContainer, modifier = Modifier.size(20.dp).padding(top = 2.dp) ) Column(verticalArrangement = Arrangement.spacedBy(4.dp)) { Text( text = stringResource(R.string.onboarding_privacy_warning_title), style = MaterialTheme.typography.bodyMedium, fontWeight = FontWeight.SemiBold, color = MaterialTheme.colorScheme.onErrorContainer ) Text( text = stringResource(R.string.onboarding_privacy_warning_desc), style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onErrorContainer ) } } } } } }
@Composable private fun ThankYouPage() { Column( modifier = Modifier .fillMaxSize() .padding(horizontal = 32.dp) .verticalScroll(rememberScrollState()), horizontalAlignment = Alignment.CenterHorizontally, verticalArrangement = Arrangement.Center ) { Icon( imageVector = Icons.Filled.Favorite, contentDescription = null, modifier = Modifier.size(72.dp), tint = MaterialTheme.colorScheme.primary ) Spacer(modifier = Modifier.height(24.dp)) Text( text = stringResource(R.string.onboarding_thank_you_title), style = MaterialTheme.typography.headlineSmall, fontWeight = FontWeight.Bold, textAlign = TextAlign.Center ) Spacer(modifier = Modifier.height(12.dp)) Text( text = stringResource(R.string.onboarding_thank_you_desc), style = MaterialTheme.typography.bodyLarge, textAlign = TextAlign.Center, color = MaterialTheme.colorScheme.onSurfaceVariant ) } }
fun iconForDataType(type: HealthDataType): ImageVector = when (type) { HealthDataType.STEPS -> Icons.AutoMirrored.Filled.DirectionsWalk HealthDataType.DISTANCE -> Icons.Filled.Straighten HealthDataType.ACTIVE_CALORIES -> Icons.Filled.LocalFireDepartment HealthDataType.TOTAL_CALORIES -> Icons.Filled.Whatshot HealthDataType.EXERCISE -> Icons.Filled.FitnessCenter HealthDataType.HEART_RATE -> Icons.Filled.MonitorHeart HealthDataType.HEART_RATE_VARIABILITY -> Icons.AutoMirrored.Filled.ShowChart HealthDataType.RESTING_HEART_RATE -> Icons.Filled.Favorite HealthDataType.BLOOD_PRESSURE -> Icons.Filled.Bloodtype HealthDataType.BLOOD_GLUCOSE -> Icons.Filled.Bloodtype HealthDataType.OXYGEN_SATURATION -> Icons.Filled.Air HealthDataType.RESPIRATORY_RATE -> Icons.Filled.Air HealthDataType.BODY_TEMPERATURE -> Icons.Filled.DeviceThermostat HealthDataType.SKIN_TEMPERATURE -> Icons.Filled.NightsStay HealthDataType.SLEEP -> Icons.Filled.Bedtime HealthDataType.WEIGHT -> Icons.Filled.MonitorWeight HealthDataType.HEIGHT -> Icons.Filled.Height HealthDataType.BODY_FAT -> Icons.Filled.MonitorWeight HealthDataType.LEAN_BODY_MASS -> Icons.Filled.FitnessCenter HealthDataType.BONE_MASS -> Icons.Filled.Accessibility HealthDataType.BASAL_METABOLIC_RATE -> Icons.Filled.LocalFireDepartment HealthDataType.VO2_MAX -> Icons.Filled.Speed HealthDataType.NUTRITION -> Icons.Filled.Restaurant HealthDataType.HYDRATION -> Icons.Filled.WaterDrop }
@Composable private fun FeatureRow(icon: ImageVector, title: String, description: String) { Row( modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(16.dp), verticalAlignment = Alignment.Top ) { Icon( imageVector = icon, contentDescription = null, tint = MaterialTheme.colorScheme.primary, modifier = Modifier .size(24.dp) .padding(top = 2.dp) ) Column { Text(text = title, style = MaterialTheme.typography.bodyMedium, fontWeight = FontWeight.Medium) Text(text = description, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant) } } }
@Composable fun LanguageSelector() { var expanded by remember { mutableStateOf(false) }
val languages = listOf( "" to "System Default", "en" to "English", "ta" to "தமிழ்", // Tamil "fr" to "Français", // French "de" to "Deutsch", // German "es" to "Español", // Spanish "pt" to "Português", // Portuguese "zh" to "中文", // Chinese "ja" to "日本語", // Japanese "ko" to "한국어", // Korean "it" to "Italiano" // Italian )
Box(modifier = Modifier.wrapContentSize(Alignment.TopEnd)) { IconButton(onClick = { expanded = true }) { Icon(Icons.Filled.Translate, contentDescription = "Select Language") } DropdownMenu( expanded = expanded, onDismissRequest = { expanded = false } ) { languages.forEach { (tag, name) -> DropdownMenuItem( text = { Text(name) }, onClick = { if (tag.isEmpty()) { AppCompatDelegate.setApplicationLocales(LocaleListCompat.getEmptyLocaleList()) } else { AppCompatDelegate.setApplicationLocales(LocaleListCompat.forLanguageTags(tag)) } expanded = false } ) } } } }

package com.hcwebhook.app.screens

import androidx.compose.animation.animateColorAsState
import androidx.compose.foundation.ExperimentalFoundationApi
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.pager.HorizontalPager
import androidx.compose.foundation.pager.rememberPagerState
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.CheckCircle
import androidx.compose.material.icons.filled.Favorite
import androidx.compose.material.icons.filled.Lock
import androidx.compose.material.icons.filled.PhoneAndroid
import androidx.compose.material.icons.filled.Timer
import androidx.compose.material.icons.filled.Warning
import androidx.compose.material.icons.filled.Webhook
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.res.stringResource
import androidx.appcompat.app.AppCompatDelegate
import androidx.core.os.LocaleListCompat
import androidx.compose.material.icons.filled.Translate
import com.hcwebhook.app.FlavorUtils
import com.hcwebhook.app.R
import kotlinx.coroutines.launch

@OptIn(ExperimentalFoundationApi::class)
@Composable
fun OnboardingScreen(onFinish: () -> Unit) {
    val pageCount = if (FlavorUtils.isPlayStore) 4 else 3
    val lastPage = pageCount - 1
    val pagerState = rememberPagerState(pageCount = { pageCount })
    val scope = rememberCoroutineScope()
    var showSkipDialog by remember { mutableStateOf(false) }

    if (showSkipDialog) {
        AlertDialog(
            onDismissRequest = { showSkipDialog = false },
            title = { Text(stringResource(R.string.onboarding_skip_dialog_title)) },
            text = { Text(stringResource(R.string.onboarding_skip_dialog_text)) },
            confirmButton = {
                TextButton(onClick = {
                    showSkipDialog = false
                    onFinish()
                }) { Text(stringResource(R.string.onboarding_skip)) }
            },
            dismissButton = {
                TextButton(onClick = { showSkipDialog = false }) { Text(stringResource(R.string.onboarding_cancel)) }
            }
        )
    }

    Scaffold(
        contentWindowInsets = WindowInsets(0.dp),
        topBar = {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp)
                    .statusBarsPadding(),
                horizontalArrangement = Arrangement.End
            ) {
                LanguageSelector()
            }
        },
        bottomBar = {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 24.dp)
                    .padding(bottom = 32.dp, top = 16.dp),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.spacedBy(16.dp)
            ) {
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    repeat(pageCount) { index ->
                        val color by animateColorAsState(
                            targetValue = if (pagerState.currentPage == index)
                                MaterialTheme.colorScheme.primary
                            else
                                MaterialTheme.colorScheme.outlineVariant,
                            label = "dot_color"
                        )
                        Box(
                            modifier = Modifier
                                .size(if (pagerState.currentPage == index) 10.dp else 8.dp)
                                .background(color, CircleShape)
                        )
                    }
                }

                Button(
                    onClick = {
                        if (pagerState.currentPage < lastPage) {
                            scope.launch { pagerState.animateScrollToPage(pagerState.currentPage + 1) }
                        } else {
                            onFinish()
                        }
                    },
                    modifier = Modifier.fillMaxWidth()
                ) {
                    Text(if (pagerState.currentPage < lastPage) stringResource(R.string.onboarding_next) else stringResource(R.string.onboarding_get_started))
                }

                if (pagerState.currentPage < lastPage) {
                    TextButton(onClick = { showSkipDialog = true }) {
                        Text(stringResource(R.string.onboarding_skip), color = MaterialTheme.colorScheme.onSurfaceVariant)
                    }
                }
            }
        }
    ) { padding ->
        HorizontalPager(
            state = pagerState,
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .statusBarsPadding()
        ) { page ->
            when (page) {
                0 -> WelcomePage()
                1 -> HowItWorksPage()
                2 -> PrivacyPage()
                3 -> ThankYouPage()
            }
        }
    }
}

@Composable
private fun WelcomePage() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 32.dp)
            .verticalScroll(rememberScrollState()),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Icon(
            imageVector = Icons.Filled.Webhook,
            contentDescription = null,
            modifier = Modifier.size(72.dp),
            tint = MaterialTheme.colorScheme.primary
        )
        Spacer(modifier = Modifier.height(24.dp))
        Text(
            text = "Usage Statistics Webhook",
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(12.dp))
        Text(
            text = "Track your daily screen time per app and sync it to your webhook endpoint automatically.",
            style = MaterialTheme.typography.bodyLarge,
            textAlign = TextAlign.Center,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
        Spacer(modifier = Modifier.height(32.dp))
        FeatureRow(
            icon = Icons.Filled.Timer,
            title = "Screen Time Tracking",
            description = "Monitors daily per-app usage via Android's UsageStatsManager"
        )
        Spacer(modifier = Modifier.height(16.dp))
        FeatureRow(
            icon = Icons.Filled.Webhook,
            title = "Webhook Sync",
            description = "Pushes JSON payloads to n8n or any HTTP endpoint"
        )
        Spacer(modifier = Modifier.height(16.dp))
        FeatureRow(
            icon = Icons.Filled.Lock,
            title = "Privacy First",
            description = "Data stays on your device until you choose to sync"
        )
    }
}

@Composable
private fun HowItWorksPage() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 24.dp)
            .padding(bottom = 24.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Icon(
            imageVector = Icons.Filled.PhoneAndroid,
            contentDescription = null,
            modifier = Modifier.size(72.dp),
            tint = MaterialTheme.colorScheme.primary
        )
        Spacer(modifier = Modifier.height(24.dp))
        Text(
            text = "How It Works",
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(12.dp))
        Text(
            text = "This app collects daily screen time data for each app on your device and formats it as a clean JSON payload.",
            style = MaterialTheme.typography.bodyLarge,
            textAlign = TextAlign.Center,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
        Spacer(modifier = Modifier.height(24.dp))

        val steps = listOf(
            "Grant Usage Access permission in system settings",
            "Configure your webhook URL(s)",
            "Set your preferred sync schedule",
            "Data syncs automatically in the background"
        )

        steps.forEachIndexed { index, step ->
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 12.dp),
                horizontalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                Text(
                    text = "${index + 1}.",
                    style = MaterialTheme.typography.bodyMedium,
                    fontWeight = FontWeight.Bold,
                    color = MaterialTheme.colorScheme.primary
                )
                Text(
                    text = step,
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
    }
}

@Composable
private fun PrivacyPage() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 32.dp)
            .verticalScroll(rememberScrollState()),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Icon(
            imageVector = Icons.Filled.Lock,
            contentDescription = null,
            modifier = Modifier.size(72.dp),
            tint = MaterialTheme.colorScheme.primary
        )
        Spacer(modifier = Modifier.height(24.dp))
        Text(
            text = stringResource(R.string.onboarding_privacy_title),
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(12.dp))
        Text(
            text = "Your data is processed locally and only sent to webhook URLs you configure.",
            style = MaterialTheme.typography.bodyLarge,
            textAlign = TextAlign.Center,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
        Spacer(modifier = Modifier.height(32.dp))

        val points = listOf(
            "No data collection by the app developer",
            "No third-party analytics or tracking",
            "Open source — inspect the code yourself",
            "Data only goes where YOU configure it",
            "Fully offline capable"
        )

        points.forEach { point ->
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(bottom = 12.dp),
                horizontalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                Icon(
                    imageVector = Icons.Filled.CheckCircle,
                    contentDescription = null,
                    tint = MaterialTheme.colorScheme.primary,
                    modifier = Modifier
                        .size(20.dp)
                        .padding(top = 2.dp)
                )
                Text(
                    text = point,
                    style = MaterialTheme.typography.bodyMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
    }
}

@Composable
private fun ThankYouPage() {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(horizontal = 32.dp)
            .verticalScroll(rememberScrollState()),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Center
    ) {
        Icon(
            imageVector = Icons.Filled.Favorite,
            contentDescription = null,
            modifier = Modifier.size(72.dp),
            tint = MaterialTheme.colorScheme.primary
        )
        Spacer(modifier = Modifier.height(24.dp))
        Text(
            text = stringResource(R.string.onboarding_thank_you_title),
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            textAlign = TextAlign.Center
        )
        Spacer(modifier = Modifier.height(12.dp))
        Text(
            text = stringResource(R.string.onboarding_thank_you_desc),
            style = MaterialTheme.typography.bodyLarge,
            textAlign = TextAlign.Center,
            color = MaterialTheme.colorScheme.onSurfaceVariant
        )
    }
}

@Composable
private fun FeatureRow(icon: ImageVector, title: String, description: String) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.spacedBy(16.dp),
        verticalAlignment = Alignment.Top
    ) {
        Icon(
            imageVector = icon,
            contentDescription = null,
            tint = MaterialTheme.colorScheme.primary,
            modifier = Modifier
                .size(24.dp)
                .padding(top = 2.dp)
        )
        Column {
            Text(text = title, style = MaterialTheme.typography.bodyMedium, fontWeight = FontWeight.Medium)
            Text(text = description, style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)
        }
    }
}

@Composable
fun LanguageSelector() {
    var expanded by remember { mutableStateOf(false) }

    val languages = listOf(
        "" to "System Default",
        "en" to "English",
        "ta" to "தமிழ்",
        "fr" to "Français",
        "de" to "Deutsch",
        "es" to "Español",
        "pt" to "Português",
        "zh" to "中文",
        "ja" to "日本語",
        "ko" to "한국어",
        "it" to "Italiano"
    )

    Box(modifier = Modifier.wrapContentSize(Alignment.TopEnd)) {
        IconButton(onClick = { expanded = true }) {
            Icon(Icons.Filled.Translate, contentDescription = "Select Language")
        }
        DropdownMenu(
            expanded = expanded,
            onDismissRequest = { expanded = false }
        ) {
            languages.forEach { (tag, name) ->
                DropdownMenuItem(
                    text = { Text(name) },
                    onClick = {
                        if (tag.isEmpty()) {
                            AppCompatDelegate.setApplicationLocales(LocaleListCompat.getEmptyLocaleList())
                        } else {
                            AppCompatDelegate.setApplicationLocales(LocaleListCompat.forLanguageTags(tag))
                        }
                        expanded = false
                    }
                )
            }
        }
    }
}

package com.hcwebhook.app

import android.content.Context
import android.content.SharedPreferences
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json

enum class SyncMode {
    INTERVAL,    // Continuous sync at specified interval
    SCHEDULED    // Sync at specific times (morning & evening)
}

class PreferencesManager(context: Context) {

    private val prefs: SharedPreferences = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    companion object {
        private const val PREFS_NAME = "hc_webhook_prefs"
        private const val KEY_LAST_SYNC_TS_PREFIX = "last_sync_ts_"
        private const val KEY_LAST_STEPS_SYNC_TS = "last_steps_sync_ts"
        private const val KEY_LAST_SLEEP_SYNC_TS = "last_sleep_sync_ts"
        private const val KEY_SYNC_INTERVAL_MINUTES = "sync_interval_minutes"
        private const val KEY_WEBHOOK_URLS = "webhook_urls"
        private const val KEY_WEBHOOK_CONFIGS = "webhook_configs"
        private const val KEY_ENABLED_DATA_TYPES = "enabled_data_types"
        private const val KEY_WEBHOOK_LOGS = "webhook_logs"
        private const val KEY_LAST_SYNC_TIME = "last_sync_time"
        private const val KEY_LAST_SYNC_SUMMARY = "last_sync_summary"
        private const val DEFAULT_SYNC_INTERVAL_MINUTES = 60
        private const val MAX_LOGS = 100
        private const val KEY_SCHEDULED_SYNC_ENABLED = "scheduled_sync_enabled"
        private const val KEY_MORNING_SYNC_HOUR = "morning_sync_hour"
        private const val KEY_MORNING_SYNC_MINUTE = "morning_sync_minute"
        private const val KEY_EVENING_SYNC_HOUR = "evening_sync_hour"
        private const val KEY_EVENING_SYNC_MINUTE = "evening_sync_minute"
        private const val KEY_SYNC_MODE = "sync_mode"
        private const val KEY_SCHEDULED_SYNCS = "scheduled_syncs"
        private const val KEY_KNOWN_GRANTED_PERMISSIONS = "known_granted_permissions"
        private const val KEY_HAS_SEEN_ONBOARDING = "has_seen_onboarding"
        private const val KEY_LAST_SEEN_VERSION_CODE = "last_seen_version_code"
        private const val KEY_LOCAL_TCP_ENABLED = "local_tcp_enabled"
        private const val KEY_LOCAL_TCP_PORT = "local_tcp_port"
        private const val DEFAULT_LOCAL_TCP_PORT = 8787
        private const val KEY_LOCAL_HTTP_AUTH_ENABLED = "local_http_auth_enabled"
        private const val KEY_LOCAL_HTTP_TOKEN = "local_http_token"
        private const val KEY_NOTIFICATION_CONFIGS = "notification_configs"
    }


    fun getLastStepsSyncTimestamp(): Long? {
        val timestamp = prefs.getLong(KEY_LAST_STEPS_SYNC_TS, -1)
        return if (timestamp == -1L) null else timestamp
    }

    fun setLastStepsSyncTimestamp(timestamp: Long) {
        prefs.edit().putLong(KEY_LAST_STEPS_SYNC_TS, timestamp).apply()
    }

    fun getLastSleepSyncTimestamp(): Long? {
        val timestamp = prefs.getLong(KEY_LAST_SLEEP_SYNC_TS, -1)
        return if (timestamp == -1L) null else timestamp
    }

    fun setLastSleepSyncTimestamp(timestamp: Long) {
        prefs.edit().putLong(KEY_LAST_SLEEP_SYNC_TS, timestamp).apply()
    }

    fun getSyncIntervalMinutes(): Int {
        return prefs.getInt(KEY_SYNC_INTERVAL_MINUTES, DEFAULT_SYNC_INTERVAL_MINUTES)
    }

    fun setSyncIntervalMinutes(minutes: Int) {
        prefs.edit().putInt(KEY_SYNC_INTERVAL_MINUTES, minutes).apply()
    }

    fun getWebhookUrls(): List<String> {
        val urlsString = prefs.getString(KEY_WEBHOOK_URLS, "") ?: ""
        return if (urlsString.isEmpty()) emptyList() else urlsString.split(",")
    }

    fun setWebhookUrls(urls: List<String>) {
        val urlsString = urls.joinToString(",")
        prefs.edit().putString(KEY_WEBHOOK_URLS, urlsString).apply()
    }

    fun getWebhookConfigs(): List<WebhookConfig> {
        val configsJson = prefs.getString(KEY_WEBHOOK_CONFIGS, null)

        // If we have new format configs, use them
        if (configsJson != null) {
            return try {
                Json.decodeFromString<List<WebhookConfig>>(configsJson)
            } catch (e: Exception) {
                // If JSON parsing fails, fall back to old format
                getWebhookUrls().map { WebhookConfig.fromUrl(it) }
            }
        }

        // Fall back to old format for backward compatibility
        return getWebhookUrls().map { WebhookConfig.fromUrl(it) }
    }

    fun setWebhookConfigs(configs: List<WebhookConfig>) {
        val configsJson = Json.encodeToString(configs)
        prefs.edit().putString(KEY_WEBHOOK_CONFIGS, configsJson).apply()

        // Also update old format for backward compatibility
        val urls = configs.map { it.url }
        setWebhookUrls(urls)
    }


    fun getEnabledDataTypes(): Set<String> {
        val typesString = prefs.getString(KEY_ENABLED_DATA_TYPES, "") ?: ""
        return if (typesString.isEmpty()) {
            emptySet()
        } else {
            typesString.split(",").filter { it.isNotBlank() }.toSet()
        }
    }

    fun setEnabledDataTypes(types: Set<String>) {
        val typesString = types.joinToString(",")
        prefs.edit().putString(KEY_ENABLED_DATA_TYPES, typesString).apply()
    }

    fun getKnownGrantedPermissions(): Set<String> {
        return prefs.getStringSet(KEY_KNOWN_GRANTED_PERMISSIONS, emptySet()) ?: emptySet()
    }

    fun setKnownGrantedPermissions(permissions: Set<String>) {
        prefs.edit().putStringSet(KEY_KNOWN_GRANTED_PERMISSIONS, permissions).apply()
    }

    fun getLastSyncTimestamp(type: String): Long? {
        val timestamp = prefs.getLong(KEY_LAST_SYNC_TS_PREFIX + type, -1)
        return if (timestamp == -1L) null else timestamp
    }

    fun setLastSyncTimestamp(type: String, timestamp: Long) {
        prefs.edit().putLong(KEY_LAST_SYNC_TS_PREFIX + type, timestamp).apply()
    }

    fun getWebhookLogs(): List<WebhookLog> {
        val logsJson = prefs.getString(KEY_WEBHOOK_LOGS, null) ?: return emptyList()
        return try {
            Json.decodeFromString<List<WebhookLog>>(logsJson)
        } catch (e: Exception) {
            emptyList()
        }
    }

    fun addWebhookLog(log: WebhookLog) {
        val currentLogs = getWebhookLogs().toMutableList()
        currentLogs.add(0, log) // Add to beginning

        // Keep only the most recent MAX_LOGS entries
        val trimmedLogs = currentLogs.take(MAX_LOGS)

        val logsJson = Json.encodeToString(trimmedLogs)
        prefs.edit().putString(KEY_WEBHOOK_LOGS, logsJson).apply()
    }

    fun removeWebhookLog(id: String) {
        val updated = getWebhookLogs().filter { it.id != id }
        val logsJson = Json.encodeToString(updated)
        prefs.edit().putString(KEY_WEBHOOK_LOGS, logsJson).apply()
    }

    fun removeWebhookLogs(ids: Set<String>) {
        val updated = getWebhookLogs().filter { it.id !in ids }
        prefs.edit().putString(KEY_WEBHOOK_LOGS, Json.encodeToString(updated)).apply()
    }

    fun clearWebhookLogs() {
        prefs.edit().remove(KEY_WEBHOOK_LOGS).apply()
    }

    fun isScheduledSyncEnabled(): Boolean {
        return prefs.getBoolean(KEY_SCHEDULED_SYNC_ENABLED, true)
    }

    fun setScheduledSyncEnabled(enabled: Boolean) {
        prefs.edit().putBoolean(KEY_SCHEDULED_SYNC_ENABLED, enabled).apply()
    }

    fun getMorningSyncHour(): Int = prefs.getInt(KEY_MORNING_SYNC_HOUR, 8)
    fun getMorningSyncMinute(): Int = prefs.getInt(KEY_MORNING_SYNC_MINUTE, 0)

    fun setMorningSyncTime(hour: Int, minute: Int) {
        prefs.edit()
            .putInt(KEY_MORNING_SYNC_HOUR, hour)
            .putInt(KEY_MORNING_SYNC_MINUTE, minute)
            .apply()
    }

    fun getEveningSyncHour(): Int = prefs.getInt(KEY_EVENING_SYNC_HOUR, 21)
    fun getEveningSyncMinute(): Int = prefs.getInt(KEY_EVENING_SYNC_MINUTE, 0)

    fun setEveningSyncTime(hour: Int, minute: Int) {
        prefs.edit()
            .putInt(KEY_EVENING_SYNC_HOUR, hour)
            .putInt(KEY_EVENING_SYNC_MINUTE, minute)
            .apply()
    }

    fun getSyncMode(): SyncMode {
        val modeString = prefs.getString(KEY_SYNC_MODE, SyncMode.INTERVAL.name) ?: SyncMode.INTERVAL.name
        return try {
            SyncMode.valueOf(modeString)
        } catch (e: Exception) {
            SyncMode.INTERVAL // Default to interval mode for backward compatibility
        }
    }

    fun setSyncMode(mode: SyncMode) {
        prefs.edit().putString(KEY_SYNC_MODE, mode.name).apply()
    }

    fun getScheduledSyncs(): List<ScheduledSync> {
        val syncsJson = prefs.getString(KEY_SCHEDULED_SYNCS, null)

        if (syncsJson != null) {
            return try {
                Json.decodeFromString<List<ScheduledSync>>(syncsJson)
            } catch (e: Exception) {
                // If JSON parsing fails, return default schedules
                getDefaultScheduledSyncs()
            }
        }

        // For backward compatibility, migrate from old morning/evening settings
        val morningHour = getMorningSyncHour()
        val morningMinute = getMorningSyncMinute()
        val eveningHour = getEveningSyncHour()
        val eveningMinute = getEveningSyncMinute()

        // Check if these are default values (8:00 and 21:00)
        val isDefaultValues = morningHour == 8 && morningMinute == 0 && eveningHour == 21 && eveningMinute == 0

        return if (isDefaultValues) {
            getDefaultScheduledSyncs()
        } else {
            // Migrate user's custom times
            listOf(
                ScheduledSync.create(morningHour, morningMinute, "Morning"),
                ScheduledSync.create(eveningHour, eveningMinute, "Evening")
            )
        }
    }

    fun setScheduledSyncs(syncs: List<ScheduledSync>) {
        val syncsJson = Json.encodeToString(syncs)
        prefs.edit().putString(KEY_SCHEDULED_SYNCS, syncsJson).apply()
    }

    private fun getDefaultScheduledSyncs(): List<ScheduledSync> {
        return listOf(
            ScheduledSync.create(8, 0, "Morning"),
            ScheduledSync.create(21, 0, "Evening")
        )
    }

    fun getLastSyncTime(): Long? {
        val timestamp = prefs.getLong(KEY_LAST_SYNC_TIME, -1)
        return if (timestamp == -1L) null else timestamp
    }

    fun setLastSyncTime(timestamp: Long) {
        prefs.edit().putLong(KEY_LAST_SYNC_TIME, timestamp).apply()
    }

    fun getLastSyncSummary(): String? {
        return prefs.getString(KEY_LAST_SYNC_SUMMARY, null)
    }

    fun setLastSyncSummary(summary: String) {
        prefs.edit().putString(KEY_LAST_SYNC_SUMMARY, summary).apply()
    }

    fun hasSeenOnboarding(): Boolean = prefs.getBoolean(KEY_HAS_SEEN_ONBOARDING, false)

    fun setHasSeenOnboarding() {
        prefs.edit().putBoolean(KEY_HAS_SEEN_ONBOARDING, true).apply()
    }

    fun getLastSeenVersionCode(): Int =
        prefs.getInt(KEY_LAST_SEEN_VERSION_CODE, 0)

    fun setLastSeenVersionCode(versionCode: Int) {
        prefs.edit().putInt(KEY_LAST_SEEN_VERSION_CODE, versionCode).apply()
    }

    fun isLocalTcpEnabled(): Boolean {
        return prefs.getBoolean(KEY_LOCAL_TCP_ENABLED, false)
    }

    fun setLocalTcpEnabled(enabled: Boolean) {
        prefs.edit().putBoolean(KEY_LOCAL_TCP_ENABLED, enabled).apply()
    }

    fun getLocalTcpPort(): Int {
        val configuredPort = prefs.getInt(KEY_LOCAL_TCP_PORT, DEFAULT_LOCAL_TCP_PORT)
        return if (configuredPort in 1024..65535) configuredPort else DEFAULT_LOCAL_TCP_PORT
    }

    fun setLocalTcpPort(port: Int) {
        val safePort = port.coerceIn(1024, 65535)
        prefs.edit().putInt(KEY_LOCAL_TCP_PORT, safePort).apply()
    }

    fun isLocalHttpAuthEnabled(): Boolean = prefs.getBoolean(KEY_LOCAL_HTTP_AUTH_ENABLED, false)

    fun setLocalHttpAuthEnabled(enabled: Boolean) {
        prefs.edit().putBoolean(KEY_LOCAL_HTTP_AUTH_ENABLED, enabled).apply()
    }

    fun getLocalHttpToken(): String {
        val existing = prefs.getString(KEY_LOCAL_HTTP_TOKEN, null)
        if (!existing.isNullOrBlank()) return existing
        val generated = java.util.UUID.randomUUID().toString()
        prefs.edit().putString(KEY_LOCAL_HTTP_TOKEN, generated).apply()
        return generated
    }

    fun regenerateLocalHttpToken(): String {
        val token = java.util.UUID.randomUUID().toString()
        prefs.edit().putString(KEY_LOCAL_HTTP_TOKEN, token).apply()
        return token
    }

    fun getNotificationConfigs(): List<NotificationConfig> {
        val configsJson = prefs.getString(KEY_NOTIFICATION_CONFIGS, null)
        if (configsJson != null) {
            return try {
                Json.decodeFromString<List<NotificationConfig>>(configsJson)
            } catch (e: Exception) {
                emptyList()
            }
        }
        return emptyList()
    }

    fun setNotificationConfigs(configs: List<NotificationConfig>) {
        val configsJson = Json.encodeToString(configs)
        prefs.edit().putString(KEY_NOTIFICATION_CONFIGS, configsJson).apply()
    }

    // -------------------------------------------------------------------------
    // Export / Import
    // -------------------------------------------------------------------------

    /**
     * Builds a [SettingsExport] snapshot of all current user-configurable preferences.
     */
    fun exportSettings(): SettingsExport {
        return SettingsExport(
            exportedAt = System.currentTimeMillis(),
            webhookConfigs = getWebhookConfigs(),
            enabledDataTypes = getEnabledDataTypes().map { it.name },
            syncMode = getSyncMode().name,
            syncIntervalMinutes = getSyncIntervalMinutes(),
            scheduledSyncs = getScheduledSyncs(),
            localTcpEnabled = isLocalTcpEnabled(),
            localTcpPort = getLocalTcpPort(),
            notificationConfigs = getNotificationConfigs()
        )
    }

    /**
     * Restores all user-configurable preferences from a [SettingsExport].
     */
    fun importSettings(export: SettingsExport) {
        setWebhookConfigs(export.webhookConfigs)

        setEnabledDataTypes(export.enabledDataTypes.toSet())

        val mode = try { SyncMode.valueOf(export.syncMode) } catch (e: Exception) { SyncMode.INTERVAL }
        setSyncMode(mode)

        setSyncIntervalMinutes(export.syncIntervalMinutes)
        setScheduledSyncs(export.scheduledSyncs)
        setLocalTcpEnabled(export.localTcpEnabled)
        setLocalTcpPort(export.localTcpPort)
        setNotificationConfigs(export.notificationConfigs)
    }
}

